mapper.select:
select s.Schedule_ID as scheduleId, cl.Class_Name as className, t.Teacher_Name as teacherName, c.Course_Name as courseName, cr.Classroom_Name as classroomName, s.Schedule_Weekday as weekday, s.Schedule_Section as section, s.Schedule_Week as week from schedule s left join class cl on s.Class_ID = cl.Class_ID left join teacher t on s.Teacher_ID = t.Teacher_ID left join course c on s.Course_ID = c.Course_ID left join classroom cr on s.Classroom_ID = cr.Classroom_ID
and s.Schedule_Week = #{week}
and s.Class_ID = #{classId}
and s.Teacher_ID = #{teacherId}
order by s.Schedule_Weekday, s.Schedule_Section, s.Schedule_ID
